b'import argparse\nfrom converters import celsius_to_fahrenheit, fahrenheit_to_celsius, celsius_to_kelvin\n\ndef convert(value, from_unit, to_unit):\n    if from_unit == to_unit:\n        return value\n    if from_unit == "celsius" and to_unit == "fahrenheit":\n        return celsius_to_fahrenheit(value)\n    elif from_unit == "celsius" and to_unit == "kelvin":\n        return celsius_to_kelvin(value)\n    elif from_unit == "fahrenheit" and to_unit == "celsius":\n        return fahrenheit_to_celsius(value)\n    elif from_unit == "fahrenheit" and to_unit == "kelvin":\n        celsius = fahrenheit_to_celsius(value)\n        return celsius_to_kelvin(celsius)\n    elif from_unit == "kelvin" and to_unit == "celsius":\n        return value - 273.15\n    elif from_unit == "kelvin" and to_unit == "fahrenheit":\n        celsius = value - 273.15\n        return celsius_to_fahrenheit(celsius)\n    else:\n        raise ValueError(f"Unsupported conversion: {from_unit} to {to_unit}")\n\nif __name__ == "__main__":\n    parser = argparse.ArgumentParser(description="Convert temperatures between units.")\n    parser.add_argument("--value", type=float, required=True, help="The temperature value to convert.")\n    parser.add_argument("--from", type=str, required=True, choices=["celsius", "fahrenheit", "kelvin"], help="The unit to convert from.")\n    parser.add_argument("--to", type=str, required=True, choices=["celsius", "fahrenheit", "kelvin"], help="The unit to convert to.")\n    args = parser.parse_args()\n\n    try:\n        result = convert(args.value, args.from, args.to)\n        print(f"{args.value} {args.from} = {result} {args.to}")\n    except ValueError as e:\n        print(f"Error: {e}")\n'